  ('police-8b7f1efc-moex-00677', 'police-8b7f1efc', 'police-8b7f1efc-moex-110-9d260bf1', 'sub-police-8b7f1efc-03', NULL, 'single_choice', '依據治安顧慮人口查訪辦法，警察機關對治安顧慮人口，多久要實施查訪一次？', '["半個月", "1個月", "2個月", "3個月"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:16+00:00", "source_pdf_sha1": "d817fc9ad8ab", "answer_pdf_sha1": "26315a0150c8", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "501", "s": "1208", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察學與警察勤務", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00678', 'police-8b7f1efc', 'police-8b7f1efc-moex-110-9d260bf1', 'sub-police-8b7f1efc-03', NULL, 'single_choice', '警察勤務條例規定服勤時數以8小時為原則，必要時，得視實際情形酌量延長之。下列敘述，何 者錯誤？', '["條文中之「必要時」係屬不確定法律概念，行政機關仍應以8小時勤務排班為宜", "行政機關仍有相當程度之判斷餘地，惟應符合比例原則", "內政部警政署有函釋避免每日常態性編排連續12小時勤務", "警察勤務要控制適當機動警力，以備勤替班，協助突發事件處理，24小時運作，有效維持治安"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:16+00:00", "source_pdf_sha1": "d817fc9ad8ab", "answer_pdf_sha1": "26315a0150c8", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "501", "s": "1208", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察學與警察勤務", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 19, "answer_corrected": true, "flags": ["answer_corrected_skip_v1"], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00679', 'police-8b7f1efc', 'police-8b7f1efc-moex-110-9d260bf1', 'sub-police-8b7f1efc-03', NULL, 'single_choice', '依據警察職權行使法規定，警察機關扣留之物得予變賣，下列有關敘述，何者錯誤？', '["有腐壞或價值重大減損之虞", "保管、照料或持有所費過鉅或有其困難", "扣留期間逾6個月，無法返還所有人、持有人或保管人，且不再合於扣留之要件", "經通知2個月內領取，且註明未於期限內領取，將予變賣，而所有人、持有人或保管人未於期 限內領取"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:16+00:00", "source_pdf_sha1": "d817fc9ad8ab", "answer_pdf_sha1": "26315a0150c8", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "501", "s": "1208", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察學與警察勤務", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00680', 'police-8b7f1efc', 'police-8b7f1efc-moex-110-9d260bf1', 'sub-police-8b7f1efc-03', NULL, 'single_choice', '警察實施治安顧慮人口查訪，應遵守有關事項，下列敘述，何者錯誤？', '["警察實施訪查，應於日間為之，但與查訪對象約定者，不在此限", "警察實施訪查時，應著制服或出示證件表明身分，並應告知事由", "警察發現查訪對象有違法之虞時，應暗中蒐集情報資料，待其犯法時，繩之以法", "發現他轄行方不明治安顧慮人口，應通報其戶籍地警察機關"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:16+00:00", "source_pdf_sha1": "d817fc9ad8ab", "answer_pdf_sha1": "26315a0150c8", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "501", "s": "1208", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察學與警察勤務", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00681', 'police-8b7f1efc', 'police-8b7f1efc-moex-110-9d260bf1', 'sub-police-8b7f1efc-03', NULL, 'single_choice', '依警察勤務區訪查作業規定，警勤區訪查工作項目之為民服務項下，包括執行失蹤人口查尋等； 依現行失蹤人口查尋作業要點，有關失蹤人口報案作業相關規定，下列敘述何者正確？', '["在臺無親屬者，依相關權責單位人員或經居住地之戶政事務所之報案辦理查尋", "社政機關或其委託公、私立社福安置機構所安置之保護個案，依該管機關（構）之報案辦理查尋", "緊急案件依其同行人員之報案，應即與其家長（法定代理人）、家屬或親屬聯繫確認後辦理查尋", "家屬委由公、私立社福安置機構照顧之個案，依安置機構之報案，並即與其家屬聯繫確認後辦 理查尋"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:16+00:00", "source_pdf_sha1": "d817fc9ad8ab", "answer_pdf_sha1": "26315a0150c8", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "501", "s": "1208", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察學與警察勤務", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00682', 'police-8b7f1efc', 'police-8b7f1efc-moex-110-9d260bf1', 'sub-police-8b7f1efc-03', NULL, 'single_choice', '邇來警察行使職權出現「黑衣人闖警局私了」、「因陌生臉孔而盤查」等事件，引發警察對於具體 個案適用法律的認知與裁量等爭議。參照翁岳生教授認為法律在個案適用過程的見解，下列敘述 何者錯誤？', '["確定事實：屬事實的判斷，是認知問題，不是裁量行為", "解釋法律：適用機關本身解釋法律是一種認知作用，不是裁量行為", "涵攝過程：將已確定的事實，套用至法律的過程，屬裁量的作用", "決定法律效果：符合要件後，決定如何處理的問題，屬裁量的行為"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:16+00:00", "source_pdf_sha1": "d817fc9ad8ab", "answer_pdf_sha1": "26315a0150c8", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "501", "s": "1208", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察學與警察勤務", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00683', 'police-8b7f1efc', 'police-8b7f1efc-moex-110-9d260bf1', 'sub-police-8b7f1efc-03', NULL, 'single_choice', '警察人員使用防護型應勤裝備時（如辣椒水）的注意事項，下列何者錯誤？', '["使用防護型應勤裝備時，應該注意風向", "無須考量地形與地物狀況，以完成任務為首要目標", "逮捕相對人後，避免其臉部接觸地面影響呼吸", "使用原因已消滅，應立即停止使用"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:16+00:00", "source_pdf_sha1": "d817fc9ad8ab", "answer_pdf_sha1": "26315a0150c8", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "501", "s": "1208", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察學與警察勤務", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00684', 'police-8b7f1efc', 'police-8b7f1efc-moex-110-9d260bf1', 'sub-police-8b7f1efc-03', NULL, 'single_choice', '警察勤務的基本原理，下列相關敘述，何者錯誤？', '["警察勤務的基本原理包括勤務組織原理與勤務運作原理", "警察勤務的組織是散在原理與授權原理而建立", "警察勤務之運作脫不了迅速原理、機動原理、彈性原理與顯見原理的支配", "警察勤務通常為警察機關服從領導者旨意之手段與方式"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:16+00:00", "source_pdf_sha1": "d817fc9ad8ab", "answer_pdf_sha1": "26315a0150c8", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "501", "s": "1208", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察學與警察勤務", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00685', 'police-8b7f1efc', 'police-8b7f1efc-moex-110-bf57eeea', 'sub-police-8b7f1efc-04', NULL, 'essay', '坊間許多公共政策或政策分析教科書，對於政府失靈都有許多解釋，例
